import{_ as r,o as e,c as l,a0 as a}from"./chunks/framework.Dx25mwie.js";const x=JSON.parse('{"title":"西班牙海鮮飯（Paella）— Afterwork Kitchen 不失敗版","description":"Afterwork Kitchen 的詳細 Paella 做法，自熬蝦湯、番紅花、飯焦 Socarrat 秘訣，一鍋到底宴客好菜。","frontmatter":{"title":"西班牙海鮮飯（Paella）— Afterwork Kitchen 不失敗版","description":"Afterwork Kitchen 的詳細 Paella 做法，自熬蝦湯、番紅花、飯焦 Socarrat 秘訣，一鍋到底宴客好菜。"},"headers":[],"relativePath":"docs/西式/西班牙海鮮飯_AfterworkKitchen.md","filePath":"docs/西式/西班牙海鮮飯_AfterworkKitchen.md"}'),n={name:"docs/西式/西班牙海鮮飯_AfterworkKitchen.md"};function o(d,t,i,s,g,h){return e(),l("div",null,[...t[0]||(t[0]=[a('<h1 id="西班牙海鮮飯-paella-—-afterwork-kitchen-不失敗版" tabindex="-1">西班牙海鮮飯（Paella）— Afterwork Kitchen 不失敗版 <a class="header-anchor" href="#西班牙海鮮飯-paella-—-afterwork-kitchen-不失敗版" aria-label="Permalink to &quot;西班牙海鮮飯（Paella）— Afterwork Kitchen 不失敗版&quot;">​</a></h1><blockquote><p><strong>來源</strong>: <a href="https://www.afterwork-kitchen.com/recipes/spanish-paella" target="_blank" rel="noreferrer">Afterwork Kitchen</a><strong>頻道</strong>: Afterwork Kitchen（放工煮好餸） <strong>分享日期</strong>: 2026/06/08 <strong>分類</strong>: 西式/西班牙</p></blockquote><hr><h2 id="成功-5-要點" tabindex="-1">成功 5 要點 <a class="header-anchor" href="#成功-5-要點" aria-label="Permalink to &quot;成功 5 要點&quot;">​</a></h2><ol><li>🍳 <strong>選鍋子</strong> — 闊身平底鍋或 Paella 專用鍋，飯要薄薄鋪平</li><li>🍚 <strong>選米</strong> — 西班牙 Bomba 米（不要用意大利米，澱粉太多）</li><li>🌸 <strong>番紅花</strong> — 靈魂香料，先浸湯 30 分鐘顏色更鮮黃</li><li>🦐 <strong>熬蝦湯</strong> — 蝦頭蝦殼熬高湯，才是真正的海鮮飯</li><li>🔥 <strong>飯焦（Socarrat）</strong> — 最後中大火迫出飯焦，合格指標</li></ol><hr><h2 id="📝-食材-5-6-人份" tabindex="-1">📝 食材（5-6 人份） <a class="header-anchor" href="#📝-食材-5-6-人份" aria-label="Permalink to &quot;📝 食材（5-6 人份）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>食材</th><th style="text-align:center;">份量</th><th>備註</th></tr></thead><tbody><tr><td>西班牙米（Bomba）</td><td style="text-align:center;"><strong>200g</strong></td><td>不要用意大利米</td></tr><tr><td>洋蔥</td><td style="text-align:center;"><strong>1 個</strong></td><td>半個熬湯，半個煮飯</td></tr><tr><td>紅椒</td><td style="text-align:center;"><strong>半個</strong></td><td>切碎</td></tr><tr><td>番茄</td><td style="text-align:center;"><strong>1 個</strong></td><td>切蓉</td></tr><tr><td>蒜</td><td style="text-align:center;"><strong>2 粒</strong></td><td>切蓉</td></tr><tr><td>煙甜紅椒粉（Smoked Paprika）</td><td style="text-align:center;"><strong>1 茶匙</strong></td><td>可省略</td></tr><tr><td>番紅花</td><td style="text-align:center;"><strong>10-15 條</strong></td><td>先浸蝦湯 30 分鐘</td></tr><tr><td>蝦</td><td style="text-align:center;"><strong>8 隻</strong></td><td>去頭去殼，蝦殼熬湯</td></tr><tr><td>魷魚</td><td style="text-align:center;"><strong>1 隻</strong></td><td>去衣切圈</td></tr><tr><td>藍青口</td><td style="text-align:center;"><strong>8-10 隻</strong></td><td></td></tr><tr><td>白酒</td><td style="text-align:center;">少許</td><td></td></tr><tr><td>檸檬</td><td style="text-align:center;"><strong>1 個</strong></td><td>上桌用</td></tr><tr><td>番芫茜</td><td style="text-align:center;">數棵</td><td>裝飾</td></tr><tr><td>鹽、黑胡椒</td><td style="text-align:center;">適量</td><td></td></tr><tr><td>橄欖油</td><td style="text-align:center;">適量</td><td></td></tr></tbody></table><hr><h2 id="👨‍🍳-步驟" tabindex="-1">👨‍🍳 步驟 <a class="header-anchor" href="#👨‍🍳-步驟" aria-label="Permalink to &quot;👨‍🍳 步驟&quot;">​</a></h2><h3 id="part-1-熬蝦高湯-🦐" tabindex="-1">Part 1：熬蝦高湯 🦐 <a class="header-anchor" href="#part-1-熬蝦高湯-🦐" aria-label="Permalink to &quot;Part 1：熬蝦高湯 🦐&quot;">​</a></h3><ol><li>蝦去頭去殼，<strong>蝦頭蝦殼留用</strong></li><li>半個洋蔥切碎</li><li>鍋中爆香洋蔥碎 → 加入蝦頭蝦殼炒香，<strong>壓出蝦膏</strong></li><li>加少許白酒 Deglaze（刮起鍋底）</li><li>加 <strong>1L 水</strong>，大火煮滾，<strong>隔去浮泡</strong></li><li>轉小火煮到餘下約 <strong>500ml</strong></li><li>過濾蝦湯，<strong>加入番紅花浸 30 分鐘</strong>備用</li></ol><h3 id="part-2-備料-🥬" tabindex="-1">Part 2：備料 🥬 <a class="header-anchor" href="#part-2-備料-🥬" aria-label="Permalink to &quot;Part 2：備料 🥬&quot;">​</a></h3><ol><li>餘下半個洋蔥、紅椒、番茄切碎</li><li>魷魚去衣，洗淨印乾後切圈</li><li>蝦身用橄欖油稍為煎香 → 備用</li><li>魷魚也炒香至半熟 → 備用</li></ol><h3 id="part-3-煮飯-🍚" tabindex="-1">Part 3：煮飯 🍚 <a class="header-anchor" href="#part-3-煮飯-🍚" aria-label="Permalink to &quot;Part 3：煮飯 🍚&quot;">​</a></h3><ol><li><strong>原鍋</strong>用橄欖油爆香洋蔥至金黃色</li><li>炒紅椒及蒜蓉</li><li>加入番茄蓉<strong>慢慢煮至糊狀</strong>（釋放蔬菜甜味的關鍵）</li><li>加入煙甜紅椒粉拌炒</li><li>加入蝦湯（含番紅花）<strong>大火煮滾</strong></li><li>下鹽及黑胡椒調味</li><li>將米粒<strong>平均撒上</strong>，<strong>不要攪拌</strong>（避免釋放澱粉）</li><li>輕輕搖晃鍋子使米鋪平</li></ol><h3 id="part-4-分段烹調-⏱️" tabindex="-1">Part 4：分段烹調 ⏱️ <a class="header-anchor" href="#part-4-分段烹調-⏱️" aria-label="Permalink to &quot;Part 4：分段烹調 ⏱️&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">階段</th><th style="text-align:center;">時間</th><th style="text-align:center;">火力</th><th>動作</th></tr></thead><tbody><tr><td style="text-align:left;">① 初煮</td><td style="text-align:center;"><strong>5 分鐘</strong></td><td style="text-align:center;">中火</td><td>不翻動</td></tr><tr><td style="text-align:left;">② 加海鮮</td><td style="text-align:center;"><strong>5 分鐘</strong></td><td style="text-align:center;">中火</td><td>放上蝦、魷魚</td></tr><tr><td style="text-align:left;">③ 加青口</td><td style="text-align:center;"><strong>10 分鐘</strong></td><td style="text-align:center;">極細火</td><td>放上青口</td></tr><tr><td style="text-align:left;">④ 迫飯焦</td><td style="text-align:center;"><strong>1-1.5 分鐘</strong></td><td style="text-align:center;">中大火</td><td>🔥 關鍵步驟</td></tr><tr><td style="text-align:left;">⑤ 燜</td><td style="text-align:center;"><strong>5 分鐘</strong></td><td style="text-align:center;">熄火</td><td>加蓋燜</td></tr></tbody></table><h3 id="part-5-上桌-🎉" tabindex="-1">Part 5：上桌 🎉 <a class="header-anchor" href="#part-5-上桌-🎉" aria-label="Permalink to &quot;Part 5：上桌 🎉&quot;">​</a></h3><ol><li>撒上番芫茜碎</li><li>擺上檸檬角</li><li>原鍋上桌！</li></ol><hr><h2 id="🎯-主廚秘訣" tabindex="-1">🎯 主廚秘訣 <a class="header-anchor" href="#🎯-主廚秘訣" aria-label="Permalink to &quot;🎯 主廚秘訣&quot;">​</a></h2><ul><li>🔑 <strong>蝦頭壓出蝦膏</strong> — 熬湯時用力壓，鮮味全釋放</li><li>🔑 <strong>番茄煮到糊狀</strong> — 釋放蔬菜甜味的關鍵步驟</li><li>🔑 <strong>不攪拌米粒</strong> — 跟義大利飯不同，避免釋放澱粉</li><li>🔑 <strong>飯面沒泡泡 = 湯被吸收了</strong> — 這時轉中大火迫飯焦</li><li>🔑 <strong>沒蓋子？</strong> — 蓋錫紙 + 濕布即可</li><li>🔑 <strong>湯:米 = 2.5~3 倍</strong> — 一杯西班牙米可吸 2.5-3 杯水</li></ul><hr><p><em>由 Hermes 於 2026/06/08 整理</em></p>',25)])])}const f=r(n,[["render",o]]);export{x as __pageData,f as default};
